# tests for subscription management\n\nimport os\nimport shutil\nimport unittest\n\n# Ensure we import the module from the repository\nimport sys\nsys.path.append(os.path.abspath(os.path.join(os.path.dirname(__file__), '..', 'src'))\n\nfrom subscriptions import load_subscribers, save_subscribers, add_subscriber, remove_subscriber\n\nclass TestSubscriptions(unittest.TestCase):\n    def setUp(self):\n        # Use a temporary directory for the JSON file\n        self.test_dir = os.path.abspath(os.path.join(os.path.dirname(__file__), '..', 'data_test'))\n        os.makedirs(self.test_dir, exist_ok=True)\n        # Override the internal path used by the module\n        global _SUBSCRIBERS_PATH\n        _SUBSCRIBERS_PATH = os.path.join(self.test_dir, 'subscribers.json')\n        # Ensure clean start\n        if os.path.exists(_SUBSCRIBERS_PATH):\n            os.remove(_SUBSCRIBERS_PATH)\n\n    def tearDown(self):\n        # Clean up test files\n        if os.path.isdir(self.test_dir):\n            shutil.rmtree(self.test_dir)\n\n    def test_add_and_remove(self):\n        # start with empty list\n        self.assertEqual(load_subscribers(), [])\n        add_subscriber('alice@example.com')\n        self.assertIn('alice@example.com', load_subscribers())\n        add_subscriber('bob@example.com')\n        subs = load_subscribers()\n        self.assertIn('bob@example.com', subs)\n        self.assertEqual(len(subs), 2)\n        # adding duplicate should not duplicate\n        add_subscriber('alice@example.com')\n        self.assertEqual(len(load_subscribers()), 2)\n        # remove one\n        remove_subscriber('alice@example.com')\n        self.assertNotIn('alice@example.com', load_subscribers())\n        self.assertEqual(len(load_subscribers()), 1)\n\nif __name__ == '__main__':\n    unittest.main()\n